terraform {
  required_providers {
    internalapi = {
      source  = "mycompany/internalapi"
      version = "~> 1.0"
    }
  }
}

variable "api_token" {
  type        = string
  sensitive   = true
  description = "API token for internal API authentication"
}

provider "internalapi" {
  endpoint = "https://api.internal.example.com"
  token    = var.api_token
}

resource "internalapi_project" "main_project" {
  name = "platform-team"
  team = "infrastructure"
}
